{"code":"import subprocess

# Test Traefik API endpoints to see registered routers
for path in ['/api/http/routers', '/api/http/services', '/api/http/middlewares']:
    r = subprocess.run([
        'curl', '-s', '--max-time', '3',
        '-u', 'sunstone:hermes2024',
        f'http://127.0.0.1:8082{path}'
    ], capture_output=True, text=True, timeout=8)
    # Filter for prep-related entries
    lines = [l for l in r.stdout.split('\n') if 'prep' in l.lower()]
    if lines:
        print(f"{path}: {lines[:3]}")
    else:
        print(f"{path}: (no prep entries, code={r.returncode}, out={r.stdout[:100]})")"}

